import numpy as np

class QuantumKernel:
    """
    Simulated quantum kernel for classification.
    """

    def __init__(self, n_qubits=4, feature_map='zz'):
        self.n_qubits = n_qubits
        self.feature_map = feature_map
        self.dim = 2**n_qubits

    def encode_feature(self, x):
        """Encode classical feature vector into quantum state representation."""
        state = np.zeros(self.dim, dtype=complex)
        state[0] = 1.0  # Start in |00...0⟩

        if self.feature_map == 'zz':
            # ZZ feature map: apply rotations and ZZ entanglement
            for i in range(self.dim):
                # Single qubit rotations
                phase = 0
                for q in range(self.n_qubits):
                    bit = (i >> q) & 1
                    if bit:
                        phase += x[q % len(x)]

                # Two-qubit ZZ interactions
                for q1 in range(self.n_qubits - 1):
                    q2 = q1 + 1
                    bit1 = (i >> q1) & 1
                    bit2 = (i >> q2) & 1
                    if bit1 and bit2:
                        phase += x[q1 % len(x)] * x[q2 % len(x)]

                amplitude = np.exp(1j * phase) / np.sqrt(self.dim)
                # Add Hadamard-like superposition
                state[i] = amplitude

        elif self.feature_map == 'pauli':
            # Pauli feature map
            for i in range(self.dim):
                phase = 0
                popcount = bin(i).count('1')

                for q in range(self.n_qubits):
                    if (i >> q) & 1:
                        phase += np.pi * x[q % len(x)]

                state[i] = np.exp(1j * phase) * np.cos(popcount * np.pi / 4)

        # Normalize
        norm = np.linalg.norm(state)
        if norm > 0:
            state /= norm

        return state

    def compute_overlap(self, state1, state2):
        """Compute overlap between two quantum states."""
        inner_product = np.vdot(state1, state2)  # ⟨state1|state2⟩
        return np.abs(inner_product)**2

    def kernel(self, x1, x2):
        """Compute quantum kernel between two samples."""
        state1 = self.encode_feature(x1)
        state2 = self.encode_feature(x2)
        return self.compute_overlap(state1, state2)

    def kernel_matrix(self, X1, X2=None):
        """Compute full kernel matrix."""
        if X2 is None:
            X2 = X1
            symmetric = True
        else:
            symmetric = False

        n1, n2 = len(X1), len(X2)
        K = np.zeros((n1, n2))

        for i in range(n1):
            for j in range(n2):
                if symmetric and j < i:
                    K[i, j] = K[j, i]
                else:
                    K[i, j] = self.kernel(X1[i], X2[j])

        return K

    def compare_with_rbf(self, X, gamma=1.0):
        """Compare quantum kernel with classical RBF kernel."""
        n = len(X)
        K_quantum = self.kernel_matrix(X)
        K_rbf = np.zeros((n, n))

        for i in range(n):
            for j in range(n):
                K_rbf[i, j] = np.exp(-gamma * np.linalg.norm(X[i] - X[j])**2)

        return K_quantum, K_rbf

# Test
np.random.seed(42)
X = np.random.randn(10, 4)

print("Quantum Kernel Implementation")
print("=" * 40)

for feature_map in ['zz', 'pauli']:
    qk = QuantumKernel(n_qubits=4, feature_map=feature_map)
    K = qk.kernel_matrix(X)

    print(f"\n{feature_map.upper()} Feature Map:")
    print(f"  Kernel matrix shape: {K.shape}")
    print(f"  Diagonal (self-similarity): {np.diag(K)[:3]}")
    print(f"  Off-diagonal range: [{K[~np.eye(10, dtype=bool)].min():.4f}, {K[~np.eye(10, dtype=bool)].max():.4f}]")

import numpy as np

class QuantumFeatureMap:
    """
    Flexible quantum feature map for classification.
    """

    def __init__(self, n_qubits=4, encoding='angle', entanglement='linear'):
        self.n_qubits = n_qubits
        self.encoding = encoding
        self.entanglement = entanglement
        self.dim = 2**n_qubits

    def apply_encoding(self, x):
        """Apply data encoding to create initial state."""
        state = np.zeros(self.dim, dtype=complex)

        if self.encoding == 'angle':
            # Angle encoding: |ψ⟩ = ⊗ (cos(x_i)|0⟩ + sin(x_i)|1⟩)
            for i in range(self.dim):
                amplitude = 1.0
                for q in range(self.n_qubits):
                    bit = (i >> q) & 1
                    angle = x[q % len(x)] * np.pi / 2
                    if bit == 0:
                        amplitude *= np.cos(angle)
                    else:
                        amplitude *= np.sin(angle)
                state[i] = amplitude

        elif self.encoding == 'amplitude':
            # Amplitude encoding: embed data directly in amplitudes
            for i in range(min(len(x), self.dim)):
                state[i] = x[i]
            norm = np.linalg.norm(state)
            if norm > 0:
                state /= norm
            else:
                state[0] = 1.0

        elif self.encoding == 'iqp':
            # IQP-style encoding with quadratic terms
            for i in range(self.dim):
                phase = 0
                for q in range(self.n_qubits):
                    if (i >> q) & 1:
                        phase += x[q % len(x)]**2
                        # Add cross terms
                        for q2 in range(q+1, self.n_qubits):
                            if (i >> q2) & 1:
                                phase += x[q % len(x)] * x[q2 % len(x)]
                state[i] = np.exp(1j * phase)
            state /= np.sqrt(self.dim)
        else:
            # Default: uniform superposition
            state = np.ones(self.dim, dtype=complex) / np.sqrt(self.dim)

        return state / np.linalg.norm(state)

    def apply_entanglement(self, state):
        """Apply entanglement layer."""
        new_state = state.copy()

        if self.entanglement == 'none':
            return new_state

        # Get pairs of qubits to entangle
        pairs = []
        if self.entanglement == 'linear':
            pairs = [(q, q+1) for q in range(self.n_qubits - 1)]
        elif self.entanglement == 'circular':
            pairs = [(q, (q+1) % self.n_qubits) for q in range(self.n_qubits)]
        elif self.entanglement == 'full':
            pairs = [(q1, q2) for q1 in range(self.n_qubits) 
                     for q2 in range(q1+1, self.n_qubits)]

        # Apply CZ-like entanglement
        for q1, q2 in pairs:
            for i in range(self.dim):
                if ((i >> q1) & 1) and ((i >> q2) & 1):
                    new_state[i] *= -1  # CZ gate effect

        return new_state / np.linalg.norm(new_state)

    def get_state(self, x):
        """Get full quantum state after encoding."""
        state = self.apply_encoding(x)
        state = self.apply_entanglement(state)
        return state

    def compute_kernel(self, x1, x2):
        """Compute kernel between two samples."""
        state1 = self.get_state(x1)
        state2 = self.get_state(x2)
        return np.abs(np.vdot(state1, state2))**2

    def analyze_expressibility(self, n_samples=100):
        """Analyze the expressibility of this feature map."""
        np.random.seed(42)

        # Generate random samples
        samples = np.random.randn(n_samples, self.n_qubits) * 0.5

        # Compute pairwise kernels
        kernels = []
        for i in range(n_samples):
            for j in range(i+1, n_samples):
                k = self.compute_kernel(samples[i], samples[j])
                kernels.append(k)

        kernels = np.array(kernels)

        # Compute self-similarity for identical inputs
        self_kernels = [self.compute_kernel(samples[i], samples[i]) 
                       for i in range(min(10, n_samples))]

        stats = {
            'encoding': self.encoding,
            'entanglement': self.entanglement,
            'kernel_mean': np.mean(kernels),
            'kernel_std': np.std(kernels),
            'kernel_min': np.min(kernels),
            'kernel_max': np.max(kernels),
            'self_similarity': np.mean(self_kernels),
            'expressibility': np.std(kernels)  # Higher std = more expressive
        }

        return stats

# Test different configurations
print("Quantum Feature Map Analysis")
print("=" * 60)

configs = [
    ('angle', 'none'),
    ('angle', 'linear'),
    ('angle', 'full'),
    ('iqp', 'linear'),
    ('iqp', 'circular')
]

results = []
for enc, ent in configs:
    fm = QuantumFeatureMap(n_qubits=4, encoding=enc, entanglement=ent)
    stats = fm.analyze_expressibility(n_samples=50)
    results.append(stats)
    print(f"\n{enc.upper()}-{ent.upper()}:")
    print(f"  Kernel range: [{stats['kernel_min']:.4f}, {stats['kernel_max']:.4f}]")
    print(f"  Kernel mean±std: {stats['kernel_mean']:.4f} ± {stats['kernel_std']:.4f}")
    print(f"  Expressibility: {stats['expressibility']:.4f}")
